def _blank(ctx, message, title="无可绘制数据", filename="empty_chart.png"):
    fig, ax = ctx.plt.subplots(figsize=(6.5, 4.2))
    ax.text(0.5, 0.5, message, ha="center", va="center", fontsize=12, color="#374151")
    ax.axis("off")
    fig.tight_layout()
    return ctx.figure(fig, filename=filename, title=title)


def _tone_parts(group):
    text = str(group or "").replace("＋", "+").replace("/", "+").replace("、", "+")
    if "+" not in text:
        return None, None
    parts = []
    for part in text.split("+"):
        value = part.strip()
        if value:
            parts.append(value)
    if len(parts) < 2:
        return None, None
    return parts[0], parts[1]


def _clean(ctx, value):
    try:
        number = float(value)
    except Exception:
        return None
    if ctx.np.isfinite(number):
        return number
    return None


def _ordered_tones(items):
    tones = []
    for item in items:
        front, back = _tone_parts(item.get("group", ""))
        for tone in [front, back]:
            if tone and tone not in tones:
                tones.append(tone)
    return tones


def _point_x(syl_index, point_index):
    percent = 5.0 + point_index * 9.0
    if syl_index == 0:
        return percent
    return 100.0 + percent


def _add_time_axis(axis):
    axis.axvline(100.0, color="#666666", linewidth=1.0, linestyle="--")
    axis.set_xlim(0, 200)
    axis.set_xticks([5, 50, 95, 105, 150, 195])
    axis.set_xticklabels(["前字5%", "前字50%", "前字95%", "后字5%", "后字50%", "后字95%"])
    axis.set_ylim(0.8, 5.2)
    axis.set_yticks([1, 2, 3, 4, 5])
    axis.set_ylabel("五度值")
    axis.grid(True, linestyle="--", alpha=0.25, linewidth=0.8)


def _collect_rows(ctx, items):
    rows = []
    for item in items:
        front, back = _tone_parts(item.get("group", ""))
        if not front or not back:
            continue
        syl_t = item.get("syl_t_values", [])
        if len(syl_t) < 2:
            continue
        for syl_index in range(2):
            points = syl_t[syl_index]
            limit = min(11, len(points))
            for point_index in range(limit):
                value = _clean(ctx, points[point_index])
                if value is None:
                    continue
                rows.append({
                    "item": item,
                    "speaker": item.get("speaker_name", "发音人"),
                    "label": str(item.get("label", "")).strip(),
                    "front": front,
                    "back": back,
                    "syl": syl_index + 1,
                    "x": _point_x(syl_index, point_index),
                    "value": value,
                })
    return rows


def _mean(values):
    if not values:
        return None
    return float(sum(values) / len(values))


def _mean_ci(ctx, values):
    arr = ctx.np.asarray(values, dtype=float)
    mean = float(ctx.np.mean(arr))
    if len(values) > 1:
        std = float(ctx.np.std(arr))
    else:
        std = 0.0
    se = std / float(ctx.np.sqrt(len(values)))
    low = max(1.0, min(5.0, mean - 1.96 * se))
    high = max(1.0, min(5.0, mean + 1.96 * se))
    return mean, low, high


def _structure_for_item(item):
    for key in ["structure_main", "结构大类", "structure_type", "结构类型"]:
        value = item.get(key)
        if value:
            return str(value), str(value)
    label = str(item.get("label", "")).strip()
    mapped = STRUCTURE_MAP.get(label)
    if mapped:
        return mapped[0], mapped[1]
    return "未分类", "未分类"


def run(ctx):
    items = ctx.dataset.included_items()
    rows = _collect_rows(ctx, items)
    tones = _ordered_tones(items)
    if not rows or not tones:
        return _blank(ctx, "无有效两字组五度值数据。\n请确认工程中已有 F0/T 值分析结果。")
    grouped = {}
    for row in rows:
        key = (row["back"], row["x"])
        grouped.setdefault(key, []).append(row["value"])
    summary = {}
    for key, values in grouped.items():
        summary[key] = _mean_ci(ctx, values)
    fig, axis = ctx.plt.subplots(figsize=(11.5, 6.0))
    cmap = ctx.plt.get_cmap("tab10")
    colors = {tone: cmap(index % 10) for index, tone in enumerate(tones)}
    for tone in tones:
        points = []
        for syl in [1, 2]:
            for point_index in range(11):
                x = _point_x(syl - 1, point_index)
                key = (tone, x)
                if key in summary:
                    mean, low, high = summary[key]
                    points.append((x, mean, low, high))
        if points:
            points.sort(key=lambda pair: pair[0])
            xs = ctx.np.asarray([p[0] for p in points], dtype=float)
            ys = ctx.np.asarray([p[1] for p in points], dtype=float)
            low = ctx.np.asarray([p[2] for p in points], dtype=float)
            high = ctx.np.asarray([p[3] for p in points], dtype=float)
            axis.plot(xs, ys, color=colors[tone], marker="o", linewidth=2.0, markersize=4, label=tone)
            axis.fill_between(xs, low, high, color=colors[tone], alpha=0.13)
    _add_time_axis(axis)
    axis.set_title("按后字调类汇总的两字组平均五度值轮廓", fontsize=13, fontweight="bold")
    axis.legend(title="后字调类", ncol=min(len(tones), 8))
    fig.tight_layout()
    ctx.log(f"绘制后字调类汇总轮廓：{len(rows)} 个采样点。")
    return ctx.figure(fig, filename="图03_按后字调类汇总平均轮廓.png", title="按后字调类汇总的两字组平均五度值轮廓")
